if (typeof msg.payload !== 'string') {
    msg.payload = JSON.stringify(msg.payload);
}
// Guardar en caché de flujo para enviarlo al primer cliente que se conecte
flow.set('vfdCache', msg.payload);
return msg;

// El cliente Angular envía {"type":"sync"} justo al abrir el WebSocket
// para pedir el último dato VFD sin esperar al siguiente ciclo de polling.
// msg._session identifica al cliente concreto: el websocket out lo usará
// para enviarle la respuesta solo a él (no broadcast).
try {
    var req = JSON.parse(msg.payload);
    if (req.type !== 'sync') return null;  // ignorar mensajes que no sean sync
} catch(e) {
    return null;  // payload no es JSON válido
}

var cache = flow.get('vfdCache');
if (!cache) {
    // Aún no hay ningún dato del VFD — el cliente recibirá el primero
    // cuando el PLC publique en el topic MQTT normalmente.
    return null;
}

// Responder solo al cliente que preguntó (msg._session intacto)
msg.payload = cache;
return msg;
